import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 金剛鉤 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛鉤尊 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：鉤杖豎執於體側（鉤先落，拳覆柄中）
        金剛鉤(bi, -8.7, 33.6, 0.92, false);
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.2], [-10.4, 38.4], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.3, 肘帽: true })));
        側拳(bi, -8.7, 36.9, 2.1, 1.05);
        // 尊左：拳安腰際
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [13.0, 45.6], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        側拳(bi, 12.8, 47.9, Math.PI / 2, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-11.6, 38.0, -10.8, 38.7, -10.0, 39.4], [-11.2, 38.9, -10.4, 39.6, -9.6, 40.3]], [-10.7, 39.1]);
            腕釧(bi, [[11.9, 44.9, 13.0, 45.4, 14.1, 45.0], [11.8, 45.8, 12.9, 46.3, 14.0, 45.9]], [12.9, 45.8]);
        });
    },
});
